INSERT INTO `news` (`id`,`addtime`,`title`,`introduction`,`picture`,`pinzhongfenlei`,`content`,`name`,`headportrait`) VALUES
(1,'2026-05-01 09:00:00','2025观赏鱼流行趋势：龙鱼称王小型鱼崛起','龙鱼以38%市场份额继续领跑。孔雀鱼、灯鱼、斗鱼等小型热带鱼销量同比增长25%。智能鱼缸占比从8%增长到18%。WiFi控温器、自动喂食器成为年轻消费者标配。','upload/news_picture_new1.jpg','金龙鱼','<p>龙鱼以38%市场份额继续领跑。孔雀鱼、灯鱼、斗鱼等小型热带鱼销量同比增长25%。智能鱼缸占比从8%增长到18%。WiFi控温器、自动喂食器成为年轻消费者标配。</p>','观赏鱼资讯编辑部','upload/news_headportrait1.jpg'),
(2,'2026-05-02 10:00:00','新手养鱼必看：开缸养水完全指南','养鱼先养水。步骤：1.设备准备 2.建立硝化系统（14-21天） 3.水质检测（氨氮=0，亚硝酸盐=0） 4.分批放鱼，每次间隔一周以上。','upload/news_picture_new2.jpg',NULL,'<p>养鱼先养水。步骤：1.设备准备 2.建立硝化系统（14-21天） 3.水质检测（氨氮=0，亚硝酸盐=0） 4.分批放鱼，每次间隔一周以上。</p>','观赏鱼资讯编辑部','upload/news_headportrait2.jpg'),
(3,'2026-05-03 11:00:00','热带鱼混养攻略：最适合混养的观赏鱼组合','新手黄金搭配：孔雀鱼+月光鱼+玛丽鱼。中型缸：虎皮鱼群+彩虹鱼。混养黄金法则：1.体型差不超过3倍 2.食性相似 3.活动水层错开 4.性情不冲突 5.水质要求一致。','upload/news_picture_new3.jpg','月光鱼','<p>新手黄金搭配：孔雀鱼+月光鱼+玛丽鱼。中型缸：虎皮鱼群+彩虹鱼。混养黄金法则：1.体型差不超过3倍 2.食性相似 3.活动水层错开 4.性情不冲突 5.水质要求一致。</p>','观赏鱼资讯编辑部','upload/news_headportrait3.jpg'),
(4,'2026-05-05 08:30:00','观赏鱼常见疾病及家庭治疗方法','1.白点病：升温30-32度+甲基蓝 2.烂鳍病：换水50%+黄粉 3.水霉病：隔离+黄粉盐浴 4.肠炎：停食3天+大蒜汁拌食 5.鳃病：大量换水+福尔马林药浴。','upload/news_picture_new4.jpg',NULL,'<p>1.白点病：升温30-32度+甲基蓝 2.烂鳍病：换水50%+黄粉 3.水霉病：隔离+黄粉盐浴 4.肠炎：停食3天+大蒜汁拌食 5.鳃病：大量换水+福尔马林药浴。</p>','观赏鱼资讯编辑部','upload/news_headportrait4.jpg'),
(5,'2026-05-06 14:00:00','城市白领的新宠：办公桌上的迷你水族世界','越来越多白领在办公桌摆放迷你水族箱。15-30cm微型鱼缸销量增长40%以上。科学研究表明观看鱼缸可有效降低心率和压力荷尔蒙。','upload/news_picture_new5.jpg','孔雀鱼','<p>越来越多白领在办公桌摆放迷你水族箱。15-30cm微型鱼缸销量增长40%以上。科学研究表明观看鱼缸可有效降低心率和压力荷尔蒙。</p>','观赏鱼资讯编辑部','upload/news_headportrait5.jpg'),
(6,'2026-05-08 09:00:00','第十五届中国国际观赏鱼展在上海开幕','来自20多国超500家参展商。世界龙鱼大赛展示200余条精品，总价值超5000万元。国际造景师大赛中国选手获金奖。中国观赏鱼市场规模达478亿元同比增长12%。','upload/news_picture_new6.jpg','血红龙鱼','<p>来自20多国超500家参展商。世界龙鱼大赛展示200余条精品，总价值超5000万元。国际造景师大赛中国选手获金奖。中国观赏鱼市场规模达478亿元同比增长12%。</p>','观赏鱼资讯编辑部','upload/news_headportrait6.jpg'),
(7,'2026-05-09 10:30:00','锦鲤饲养入门：从池塘选址到日常管理','池塘面积6平方米以上，水深1-1.5米。三段式过滤系统。春季逐步增加喂食，夏季投喂高蛋白，秋季增加色扬饲料，冬季停食或少量喂小麦胚芽。','upload/news_picture_new1.jpg','锦鲤','<p>池塘面积6平方米以上，水深1-1.5米。三段式过滤系统。春季逐步增加喂食，夏季投喂高蛋白，秋季增加色扬饲料，冬季停食或少量喂小麦胚芽。</p>','观赏鱼资讯编辑部','upload/news_headportrait7.jpg'),
(8,'2026-05-10 15:00:00','智能鱼缸时代：AI如何改变养鱼方式','智能鱼缸可实现自动喂食（远程控制）、水质实时监测、自动换水、光谱可调LED灯、AI鱼病识别。智能设备不能完全替代人工观察。','upload/news_picture_new2.jpg',NULL,'<p>智能鱼缸可实现自动喂食（远程控制）、水质实时监测、自动换水、光谱可调LED灯、AI鱼病识别。智能设备不能完全替代人工观察。</p>','观赏鱼资讯编辑部','upload/news_headportrait8.jpg'),
(9,'2026-05-12 11:00:00','海水观赏鱼入门：小丑鱼与珊瑚礁生态缸','推荐60cm海水套缸起步预算5000-8000元。入门鱼种：小丑鱼、蓝魔雀鲷、黄吊、草莓、虾虎。海水缸最大坑：管不住手密度太大水质崩溃。','upload/news_picture_new3.jpg','小丑鱼','<p>推荐60cm海水套缸起步预算5000-8000元。入门鱼种：小丑鱼、蓝魔雀鲷、黄吊、草莓、虾虎。海水缸最大坑：管不住手密度太大水质崩溃。</p>','观赏鱼资讯编辑部','upload/news_headportrait1.jpg'),
(10,'2026-05-13 10:00:00','家庭养鱼的五大误区','1.缸越大越好？60-80cm甜蜜点 2.水清=水质好？需用测试剂 3.喂越多越好？2分钟吃完量 4.换水越多越干净？30-50%即可 5.自来水放一天就能用？需困水48小时。','upload/news_picture_new4.jpg',NULL,'<p>1.缸越大越好？60-80cm甜蜜点 2.水清=水质好？需用测试剂 3.喂越多越好？2分钟吃完量 4.换水越多越干净？30-50%即可 5.自来水放一天就能用？需困水48小时。</p>','观赏鱼资讯编辑部','upload/news_headportrait2.jpg');
